const staticData = $getWorkflowStaticData('global');
const item = $input.first();
const json = item.json;
const isDown = json.error !== undefined || json.code !== undefined;
let failures = staticData.consecutiveFailures || 0;
if (isDown) { failures++; } else { failures = 0; }
staticData.consecutiveFailures = failures;
const ts = new Date().toISOString();
const alertText = '\ud83e\udd9e Heartbeat Patrol \u2014 Bridge Dead Man Switch\n\n\u26a0\ufe0f Bridge DOWN \u2014 ' + failures + ' consecutive failures\nEndpoint: https://macmini-bridge.coletiv.me/health\nTimestamp: ' + ts + '\n\nMac Mini offline ou Claude auth expirou.\nAction: SSH Mac Mini \u2192 verificar estado';
return [{ json: { shouldAlert: failures >= 2, consecutiveFailures: failures, bridgeStatus: isDown ? 'DOWN' : 'UP', timestamp: ts, alertText: alertText } }];

